import { useParams, useNavigate } from "react-router-dom";
import { useState, useEffect, useContext } from "react";
import products from "../data/ProductData"; // dummy product list
import "../index.css";
import { CartContext } from "../context/CartContext"; // ✅ import cart context

function ProductDetails() {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const [mainImage, setMainImage] = useState("");
  const { addToCart, toggleCheckout } = useContext(CartContext); // ✅ use cart
  const [message, setMessage] = useState(""); // ✅ for Add to Cart message

  const navigate = useNavigate(); // for optional navigation

  useEffect(() => {
    // ✅ Check if product exists in local dummy data first
    const dummyProduct = products.find((p) => String(p.id) === id);
    if (dummyProduct) {
      setProduct(dummyProduct);
      setMainImage(dummyProduct.image);
      return;
    }

    // ✅ Else fetch from API
    fetch('http://localhost:5000/api/products/${id}')
      .then((res) => res.json())
      .then((data) => {
        setProduct(data);
        setMainImage(data.image);
      })
      .catch((err) => console.error("Error fetching product:", err));
  }, [id]);

  if (!product) {
    return <h2 className="not-found">Product Not Found</h2>;
  }

  const images = [product.image, ...(product.images || [])];

  // ✅ Add to Cart button (shows message)
  const handleAddToCart = () => {
    addToCart({
      id: product.id || product._id,
      name: product.name,
      price: product.price,
      image: product.image,
    });
    setMessage("✅ Added to Cart!");
    setTimeout(() => setMessage(""), 2000);
  };

  // ✅ Buy Now (no alert, directly opens checkout)
  const handleBuyNow = () => {
    addToCart({
      id: product.id || product._id,
      name: product.name,
      price: product.price,
      image: product.image,
    });
    toggleCheckout(); // opens the checkout drawer/panel
    // OR use navigate("/cart"); if you want to go to Cart page instead
  };

  return (
    <div className="product-details">
      {/* ✅ Floating message */}
      {message && (
        <div
          style={{
            position: "fixed",
            top: "20px",
            right: "20px",
            background: "#28a745",
            color: "#fff",
            padding: "10px 20px",
            borderRadius: "5px",
            boxShadow: "0 2px 6px rgba(0,0,0,0.3)",
            zIndex: 2000,
            animation: "slideDown 0.3s ease",
          }}
        >
          {message}
        </div>
      )}

      {/* Left: Product Images */}
      <div className="image-section">
        <div className="main-image">
          <img src={mainImage} alt={product.name} />
        </div>

        <div className="thumbnails">
          {images.map((img, idx) => (
            <div
              key={idx}
              className={'thumb ${mainImage === img ? "active" : ""}'}
              onClick={() => setMainImage(img)}
            >
              <img src={img} alt={'${product.name}-${idx}'} />
            </div>
          ))}
        </div>
      </div>

      {/* Right: Product Details */}
      <div className="details-section">
        <h1>{product.name}</h1>
        <p>{product.description}</p>

        <div className="price">
          <span className="offer">₹{product.price}</span>
          {product.oldPrice && <span className="old">₹{product.oldPrice}</span>}
        </div>

        {/* Buttons */}
        <div className="buttons">
          <button className="btn" onClick={handleAddToCart}>
            Add to Cart
          </button>
          <button className="btn buy" onClick={handleBuyNow}>
            Buy Now
          </button>
        </div>
      </div>

      {/* ✅ Slide-in animation for message */}
      <style>
        {`
          @keyframes slideDown {
            from { transform: translateY(-20px); opacity: 0; }
            to { transform: translateY(0); opacity: 1; }
          }

          .product-details {
            display: flex;
            flex-wrap: wrap;
            gap: 40px;
            padding: 40px;
            max-width: 1200px;
            margin: auto;
          }

          .image-section {
            flex: 1;
            min-width: 300px;
          }

          .main-image img {
            width: 100%;
            border-radius: 8px;
            object-fit: contain;
          }

          .thumbnails {
            display: flex;
            gap: 10px;
            margin-top: 10px;
          }

          .thumb {
            border: 2px solid transparent;
            border-radius: 6px;
            cursor: pointer;
            transition: 0.2s ease;
          }

          .thumb.active {
            border-color: #ff6d0c;
          }

          .thumb img {
            width: 60px;
            height: 60px;
            object-fit: contain;
            border-radius: 6px;
          }

          .details-section {
            flex: 1;
            min-width: 300px;
          }

          .price {
            margin: 15px 0;
          }

          .offer {
            font-size: 22px;
            font-weight: bold;
            color: #ff6d0c;
          }

          .old {
            text-decoration: line-through;
            color: #777;
            margin-left: 10px;
          }

          .buttons {
            display: flex;
            gap: 10px;
          }

          .btn {
            padding: 12px 20px;
            border: none;
            border-radius: 6px;
            cursor: pointer;
            font-size: 15px;
            background: #ff6d0c;
            color: #fff;
            transition: 0.3s;
          }

          .btn:hover {
            background: #e65a00;
          }

          .btn.buy {
            background: #e74c3c;
          }

          .btn.buy:hover {
            background: #d62c1a;
          }

          @media (max-width: 768px) {
            .product-details {
              flex-direction: column;
              padding: 20px;
            }

            .buttons {
              flex-direction: column;
            }
          }
        `}
      </style>
    </div>
  );
}

export default ProductDetails;
